+  pthread_mutex_lock(&g_state_mutex);
+
+  if (g_fuse != NULL) {
+    pthread_mutex_unlock(&g_state_mutex);
+    return -EBUSY;
+  }
+
+  if (!g_getattr_cb || !g_readdir_cb || !g_open_cb || !g_read_cb || !g_write_cb || !g_create_cb || !g_unlink_cb || !g_mkdir_cb || !g_rmdir_cb) {
