+  g_ops.readdir = bridge_op_readdir;
+  g_ops.open = bridge_op_open;
+  g_ops.read = bridge_op_read;
+  g_ops.write = bridge_op_write;
+  g_ops.create = bridge_op_create;
+  g_ops.unlink = bridge_op_unlink;
